__global__ void nw_kernel(int *input_itemsets, int *referrence, int max_cols, int blk, int penalty, int max_blocks) {
    int b_index_x = blockIdx.x * blockDim.x + threadIdx.x;
    if (b_index_x >= blk) return;

    int b_index_y = blk - 1 - b_index_x;

    if (b_index_y < 0 || b_index_y >= max_blocks) return;

    __shared__ int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    __shared__ int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    // Load reference_l
    for (int i = threadIdx.y; i < BLOCK_SIZE; i += blockDim.y) {
        for (int j = threadIdx.x; j < BLOCK_SIZE; j += blockDim.x) {
            int idx = i * BLOCK_SIZE + j;
            int ref_idx = max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1;
            reference_l[idx] = referrence[ref_idx];
        }
    }
    __syncthreads();

    // Load input_itemsets_l
    for (int i = threadIdx.y; i < BLOCK_SIZE + 1; i += blockDim.y) {
        for (int j = threadIdx.x; j < BLOCK_SIZE + 1; j += blockDim.x) {
            int idx = i * (BLOCK_SIZE + 1) + j;
            int input_idx = max_cols * (b_index_y * BLOCK_SIZE + i) + b_index_x * BLOCK_SIZE + j;
            input_itemsets_l[idx] = input_itemsets[input_idx];
        }
    }
    __syncthreads();

    // Compute
    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            int idx = i * (BLOCK_SIZE + 1) + j;
            int val = maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
            input_itemsets_l[idx] = val;
        }
    }
    __syncthreads();

    // Store back
    for (int i = threadIdx.y; i < BLOCK_SIZE; i += blockDim.y) {
        for (int j = threadIdx.x; j < BLOCK_SIZE; j += blockDim.x) {
            int idx = (i + 1) * (BLOCK_SIZE + 1) + j + 1;
            int out_idx = max_cols * (b_index_y * BLOCK_SIZE + i + 1) + b_index_x * BLOCK_SIZE + j + 1;
            input_itemsets[out_idx] = input_itemsets_l[idx];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty)
{
    int max_blocks = (max_cols - 1) / BLOCK_SIZE;

    int *d_input_itemsets, *d_referrence;
    size_t size = max_rows * max_cols * sizeof(int);

    cudaMalloc((void**)&d_input_itemsets, size);
    cudaMalloc((void**)&d_referrence, size);

    cudaMemcpy(d_input_itemsets, input_itemsets, size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_referrence, referrence, size, cudaMemcpyHostToDevice);

    dim3 blockDim(16, 16);
    for (int blk = 1; blk <= max_blocks; blk++) {
        int grid_x = blk;
        if (grid_x > 1024) grid_x = 1024; // max grid size limit
        dim3 gridDim(grid_x, 1);

        nw_kernel<<<gridDim, blockDim>>>(d_input_itemsets, d_referrence, max_cols, blk, penalty, max_blocks);
        cudaDeviceSynchronize();
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= max_blocks; blk++) {
        int grid_x = max_blocks - blk + 1;
        if (grid_x > 1024) grid_x = 1024;
        dim3 gridDim(grid_x, 1);

        nw_kernel<<<gridDim, blockDim>>>(d_input_itemsets, d_referrence, max_cols, blk, penalty, max_blocks);
        cudaDeviceSynchronize();
    }

    cudaMemcpy(input_itemsets, d_input_itemsets, size, cudaMemcpyDeviceToHost);

    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

long long get_time()
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <max_rows/max_cols> <penalty> <num_threads>\n", argv[0]);
    fprintf(stderr, "\t<dimension>      - x and y dimensions\n");
    fprintf(stderr, "\t<penalty>        - penalty(positive integer)\n");
    fprintf(stderr, "\t<num_threads>    - no. of threads\n");
    exit(1);
}

void runTest( int argc, char** argv);

int main( int argc, char** argv) 
{
    runTest( argc, argv);
    return EXIT_SUCCESS;
}

